Javascript.isReadOnly:
if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { 
				var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null) return true; }

Javascript.initialise:
var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
var def1AddrPostCode = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/PostCode");
var def2AddrPostCode = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/PostCode");
var partyAgainstAddrPostCode = "";
if(partyAgainstNumber == 1) {
	partyAgainstAddrPostCode = def1AddrPostCode;
} else {
	partyAgainstAddrPostCode = def2AddrPostCode; }
var otherPossessAddrPostCode = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/PostCode");
var possessAddrPostCode = "";			
if(otherPossessAddrPostCode != "") {
	possessAddrPostCode = otherPossessAddrPostCode;
} else {
	possessAddrPostCode = partyAgainstAddrPostCode; }
Services.setValue(PossessPostcode.dataBinding, possessAddrPostCode);
